&lt;p style=&quot;&quot;&gt;&amp;rArr; 32 = 79.5 &amp;ndash; 2 &amp;times; Mean&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&amp;rArr; Mean = 47.5/2&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&amp;rArr; Mean = 23.75&lt;/p&gt;

